import { useEffect, useState } from 'react';
import Layout from '../components/Layout';
import { bolgeAPI } from '../api';

export default function BolgeMerkezler() {
  const [merkezler, setMerkezler] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filtre, setFiltre] = useState('');
  const [tipFiltre, setTipFiltre] = useState('');

  useEffect(() => {
    bolgeAPI.getMerkezler()
      .then(r => setMerkezler(r.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const filtered = merkezler.filter(m => {
    const aramaUygun = !filtre ||
      m.ad.toLowerCase().includes(filtre.toLowerCase()) ||
      m.il.toLowerCase().includes(filtre.toLowerCase()) ||
      m.ilce?.toLowerCase().includes(filtre.toLowerCase());
    const tipUygun = !tipFiltre || m.tip === tipFiltre;
    return aramaUygun && tipUygun;
  });

  const tipLabel = (t) => t === 'toplama' ? 'Toplama' : 'Dağıtım';
  const tipBadge = (t) => t === 'toplama' ? 'badge-info' : 'badge-success';

  return (
    <Layout title="Bölge Merkezleri">
      <div className="card">
        <div className="card-header">
          <div className="card-title">Merkezler ({filtered.length})</div>
          <div style={{ display: 'flex', gap: 8 }}>
            <select
              className="form-control"
              style={{ width: 160 }}
              value={tipFiltre}
              onChange={e => setTipFiltre(e.target.value)}
            >
              <option value="">Tüm Tipler</option>
              <option value="toplama">Toplama</option>
              <option value="dagitim">Dağıtım</option>
            </select>
            <input
              className="form-control"
              placeholder="Ara (merkez adı, il...)"
              style={{ width: 220 }}
              value={filtre}
              onChange={e => setFiltre(e.target.value)}
            />
          </div>
        </div>

        {loading ? (
          <div className="loading"><div className="spinner" /> Yükleniyor...</div>
        ) : filtered.length === 0 ? (
          <div className="empty-state">
            <div className="empty-icon">🏢</div>
            <div className="empty-text">Merkez bulunamadı</div>
          </div>
        ) : (
          <div className="table-wrapper">
            <table>
              <thead>
                <tr>
                  <th>#</th>
                  <th>Merkez Adı</th>
                  <th>Tip</th>
                  <th>İl / İlçe</th>
                  <th>Yetkili</th>
                  <th>Stok Kalemi</th>
                  <th>Toplam Adet</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(m => (
                  <tr key={m.id}>
                    <td style={{ color: 'var(--text3)', fontFamily: 'IBM Plex Mono' }}>{m.id}</td>
                    <td><strong>{m.ad}</strong></td>
                    <td><span className={`badge ${tipBadge(m.tip)}`}>{tipLabel(m.tip)}</span></td>
                    <td>{m.il} / {m.ilce}</td>
                    <td>{m.yetkili_adi || <span style={{ color: 'var(--text3)' }}>—</span>}</td>
                    <td style={{ fontFamily: 'IBM Plex Mono' }}>{m.stok_kalemi_sayisi}</td>
                    <td style={{ fontFamily: 'IBM Plex Mono' }}>{m.toplam_stok_adet.toLocaleString('tr-TR')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </Layout>
  );
}
